import json
from pathlib import Path
import importlib.util

spec = importlib.util.spec_from_file_location('prov', 'stl_validator_provided.py')
prov = importlib.util.module_from_spec(spec)
spec.loader.exec_module(prov)


def cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def dot(a, b):
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2]


def mag(v):
    return (v[0]**2 + v[1]**2 + v[2]**2) ** 0.5


def parse_ascii_triangles(path):
    triangles = []
    with open(path, 'r', errors='replace') as fh:
        lines = fh.readlines()
    i = 0
    while i < len(lines):
        line = lines[i].strip()
        if line.startswith('facet normal'):
            parts = line.split()
            try:
                declared = (float(parts[2]), float(parts[3]), float(parts[4]))
            except Exception:
                i += 1
                continue
            verts = []
            i += 1
            if i < len(lines) and lines[i].strip() == 'outer loop':
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith('vertex'):
                            vp = vline.split()
                            try:
                                verts.append((float(vp[1]), float(vp[2]), float(vp[3])))
                            except Exception:
                                pass
                        i += 1
            if len(verts) == 3:
                triangles.append((declared, verts))
            continue
        i += 1
    return triangles


def inferred_reason(path):
    triangles = parse_ascii_triangles(path)
    if not triangles:
        return 'parse_error'

    degenerate = False
    inverted = False
    edge_count = {}
    for declared, verts in triangles:
        n = cross(sub(verts[1], verts[0]), sub(verts[2], verts[0]))
        nmag = mag(n)
        if nmag <= 1e-12:
            degenerate = True
        else:
            dmag = mag(declared)
            if dmag > 1e-12 and dot(n, declared) < 0:
                inverted = True
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            e = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[e] = edge_count.get(e, 0) + 1

    if degenerate:
        return 'degenerate_triangles'
    if any(c > 2 for c in edge_count.values()):
        return 'non_manifold_edges'
    if any(c == 1 for c in edge_count.values()):
        return 'open_edges'
    if inverted:
        return 'inverted_normals'
    return 'unknown_invalid'


results = []
for i in range(1, 21):
    path = f'supplier_{i:03d}.stl'
    base = prov.parse_stl(path)
    valid = base.get('valid', False)
    entry = {'file': path, 'valid': bool(valid)}
    if not valid:
        entry['reason'] = inferred_reason(path)
    else:
        reason = inferred_reason(path)
        if reason == 'inverted_normals':
            entry['valid'] = False
            entry['reason'] = reason
    results.append(entry)

report = {'results': results}
with open('validation_report.json', 'w') as fh:
    json.dump(report, fh)
print(json.dumps(report))
